import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreEmptyLinesTrue() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat newFormat = format.withIgnoreEmptyLines(true);

        assertNotNull(newFormat);
        assertTrue(newFormat.getIgnoreEmptyLines());
        // Original format unchanged
        assertTrue(format.getIgnoreEmptyLines());
        assertNotSame(format, newFormat);
    }

    @Test
    void testWithIgnoreEmptyLinesFalse() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat newFormat = format.withIgnoreEmptyLines(false);

        assertNotNull(newFormat);
        assertFalse(newFormat.getIgnoreEmptyLines());
        // Original format unchanged
        assertTrue(format.getIgnoreEmptyLines());
        assertNotSame(format, newFormat);
    }

    @Test
    void testWithIgnoreEmptyLinesDoesNotAffectOtherProperties() {
        CSVFormat format = CSVFormat.DEFAULT.withDelimiter(';').withQuote('\'').withTrim(true);
        CSVFormat newFormat = format.withIgnoreEmptyLines(false);

        assertEquals(';', newFormat.getDelimiter());
        assertEquals('\'', newFormat.getQuoteCharacter());
        assertTrue(newFormat.getTrim());
        assertFalse(newFormat.getIgnoreEmptyLines());
        // Original format unchanged
        assertTrue(format.getIgnoreEmptyLines());
    }
}
